#include<bits/stdc++.h>
using namespace std;
struct node
{
	int c=0,m=0,e=0,sum=0,num=0,ans=0;
	bool flag=0;
};
bool cmp1(node &a,node &b)
{
	if(a.sum!=b.sum) return a.sum>b.sum;
	else if((a.m+a.c)!=(b.m+b.c)) return (a.m+a.c)>(b.m+b.c);
	else if(max(a.m,a.c)!=max(b.m,b.c)) return max(a.m,a.c)>max(b.m,b.c);
	else
	{
		if(a.num<b.num) b.flag=1;
		else a.flag=1;
		return a.num<b.num;
	}
}
bool cmp2(node a,node b)
{
	return a.num<b.num;
}
node a[200005];
int n;
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i].c>>a[i].m>>a[i].e;
		a[i].sum=a[i].c+a[i].m+a[i].e;
		a[i].num=i;
	}
	sort(&a+1,&a+1+n,cmp1);
	for(int i=1;i<=n;i++)
	{
		if(a[i].ans) continue;
		else
		{
			a[i].ans=i;
			int cur=1;
			while(a[i+cur].flag)
			{
				a[i+cur].ans=a[i].ans;
				cur++;
			}
		}
	}
	sort(a+1,a+1+n,cmp2);
	for(int i=1;i<=n;i++) cout<<a[i].ans<<'\n';
	return 0;
}
